  description = 'Put validated forecasting, anomaly detection, and AI-driven insight capabilities into production within your BI and analytics environment, with governance controls and monitoring configured from the first day of operation.',
  positioning = 'Launch AI-powered analytics in production: models governed, outputs integrated into your existing dashboards, and your analytics team trained to act on what the AI surfaces.',
  hero_summary = 'Put validated forecasting, anomaly detection, and AI-driven insight capabilities into production within your BI and analytics environment, with governance controls and monitoring configured from the first day of operation.',
  overview_paragraphs = '["The Business Intelligence & Analytics AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled business intelligence and analytics workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for strategy, finance & analytics leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for business intelligence & analytics with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["AI outputs surface inside your existing BI tools, no separate interface required","Human-in-the-loop controls implemented as specified, not deferred to a later phase","Analytics team trained on model interpretation before go-live"]'::jsonb,
  why_it_matters = '{"hook":"Analytics capability determines whether decisions are driven by evidence, or by assumption.","problemParagraph":"Many AI initiatives for your analytics capability fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for business intelligence & analytics fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Common questions about the Business Intelligence and Analytics AI deployment engagement.'
WHERE variant_id = 113;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Production AI analytics deployment', 'AI models serving live predictions integrated into your BI dashboards, with version control and rollback capability confirmed working before launch.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Monitoring and alert configuration', 'Drift detection, accuracy tracking, and alerting thresholds configured so degradation is caught and investigated before it affects decisions.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Governance and audit controls', 'Audit logs covering model predictions, access controls on model endpoints, and documentation of the human review points applied in each workflow.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (113, 'Analytics team enablement pack', 'Training materials, interpretation guides, and escalation procedures giving your analytics team the confidence to act on AI outputs and challenge them when something looks wrong.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do AI insights appear inside our existing dashboards?', 'The integration architecture defined in your AI design connects model outputs to your BI tool''s data layer. Analysts see forecasts, anomaly flags, or narrative insights directly in the dashboards they already use.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'What happens when a model flags an anomaly?', 'The alert routes to the relevant analyst. The incident playbook tells them what to investigate, what to rule out, and when to escalate. The DigitalQatalyst team will support the first few live alerts to build team confidence.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do you validate that the AI is producing useful outputs before go-live?', 'We run a shadow period where models produce outputs alongside your existing analysis. Your analytics team reviews the outputs against known historical events before the model is promoted to production.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (113, 'How do we get started?', 'Share your completed AI design specifications with the DigitalQatalyst team. We will confirm infrastructure requirements, identify the first use case for deployment, and schedule a kick-off.', 3);

-- Business Intelligence & Analytics (High-Impact) - Managed (variant 114)
