INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'Production AI deployment', 'AI capabilities live in production with model versioning, staged rollout controls, and rollback capability confirmed working before any model handles live decisions.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'Monitoring and alerting platform', 'Real-time dashboards and alert configurations for model performance, input drift, prediction distribution, and infrastructure health.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'Audit and traceability controls', 'Complete audit logs covering model predictions, confidence scores, human review outcomes, and model version history, meeting the audit requirements of your governance framework.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (119, 'AI operations handover pack', 'Retraining triggers, model lifecycle management procedures, incident playbooks, and a sign-off checklist confirming your team can manage the AI capabilities independently.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'What is a shadow period and why does it matter?', 'During the shadow period, the AI produces outputs in parallel with your existing process without acting on them. Your team reviews the outputs against known outcomes to confirm the model is reliable before it takes over the decision.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'How do you handle model retraining in production?', 'The handover pack includes documented retraining triggers based on drift thresholds or scheduled frequency, the steps to retrain safely, and the validation checks that must pass before the retrained model replaces the current version.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'What audit evidence does the deployment produce?', 'Every model prediction is logged with its input features, confidence score, output, and the human review outcome where applicable. The audit log is queryable and retained for the period your governance framework requires.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (119, 'How do we get started?', 'Share your completed AI design specifications with the DigitalQatalyst team. We will confirm infrastructure requirements, validate the governance controls to implement, and agree a deployment schedule.', 3);

-- Enterprise AI & Automation (High-Impact) - Managed (variant 120)
UPDATE product_content SET
  description = 'Keep your enterprise AI and automation capabilities operating reliably and responsibly, with SLA-backed monitoring, monthly performance reporting, model lifecycle management, and a continuous improvement cycle run by the DigitalQatalyst team.',
  positioning = 'Maintain enterprise AI that your organisation can trust every month: monitored, governed, optimised, and with every model lifecycle event handled before it becomes a problem.',
  hero_summary = 'Keep your enterprise AI and automation capabilities operating reliably and responsibly, with SLA-backed monitoring, monthly performance reporting, model lifecycle management, and a continuous improvement cycle run by the DigitalQatalyst team.',
  overview_paragraphs = '["The Enterprise AI & Automation Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve enterprise AI and automation with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for ceos, cios, ai & transformation leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for enterprise ai & automation - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["SLA-backed incident response so model degradation is caught and resolved before decisions are affected","Proactive retraining management prevents the silent accuracy decay that makes AI untrustworthy over time","Governance compliance reporting gives your risk and audit teams the evidence they need each quarter"]'::jsonb,
  why_it_matters = '{"hook":"AI and automation are reshaping how organisations operate, but only where use cases are validated and governed.","problemParagraph":"Many organisations struggle to sustain performance across your AI and automation portfolio after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"enterprise ai & automation issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Common questions about the Enterprise AI and Automation managed service.'
WHERE variant_id = 120;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Monthly AI operations report', 'A performance view covering model accuracy, drift indicators, prediction volumes, incident history, and any retraining events completed during the month.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Incident log and resolution record', 'A complete log of every model degradation event, alert, or incident, with time to detect and resolve, root cause, and the preventive action applied.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Quarterly model review', 'An assessment of each model''s performance trend, retraining schedule, and fitness for continued production use, with recommendations for upgrades or retirement.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (120, 'Governance compliance report', 'A periodic confirmation that audit logging, access controls, human oversight procedures, and responsible AI requirements remain active and compliant with your governance framework.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'What SLAs apply to AI model incidents?', 'SLAs are agreed during onboarding and cover time to detect a degradation alert, time to notify the relevant team, and time to resolve or escalate by severity. Performance against SLAs is reported monthly.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'How do you decide when a model needs retraining?', 'Retraining triggers are defined in the handover documentation from the deployment engagement. The DigitalQatalyst team monitors the agreed drift and performance thresholds and initiates retraining when a trigger is met, following the validated retraining procedure.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'What happens when a regulation changes and affects our AI governance requirements?', 'Regulatory changes relevant to your AI capabilities are flagged in the quarterly governance review. The DigitalQatalyst team will assess the impact on your current controls and recommend changes, which are then handled as a managed change request.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (120, 'How do we get started?', 'The managed service follows a completed AI deployment. Contact the DigitalQatalyst team to discuss transition planning, agree SLAs, and define the service catalogue for your AI capabilities.', 3);

-- Technology Governance (High-Impact) - Assess (variant 121)
UPDATE product_content SET
  description = 'Assess the maturity of your technology governance framework across portfolio management, architecture standards, vendor oversight, and delivery controls, and receive a prioritised improvement roadmap your CIO can act on immediately.',
  positioning = 'Understand where your technology governance framework is strong and where it is creating delivery risk, cost drag, or architectural drift.',
  hero_summary = 'Assess the maturity of your technology governance framework across portfolio management, architecture standards, vendor oversight, and delivery controls, and receive a prioritised improvement roadmap your CIO can act on immediately.',
  overview_paragraphs = '["The Technology Governance Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps governance maturity and returns prioritised improvements your CIO and architecture leaders can act on.","See how technology governance performs today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for cios, enterprise architecture & pmo leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews technology governance across governance, risk, and platform reliability.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope, no-obligation assessment completed within one week","Covers portfolio, architecture, vendor, and delivery governance in a single engagement","Board-ready improvement roadmap delivered before the engagement closes"]'::jsonb,
  why_it_matters = '{"hook":"Technology governance is what turns ambitious delivery into sustainable, risk-aware progress.","problemParagraph":"Many organisations govern technology informally, with unclear architecture decisions, weak standards adoption, and limited portfolio visibility. This assessment maps governance maturity and returns prioritised improvements your CIO and architecture leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Ad hoc architecture decisions","description":"Standards are bypassed when delivery pressure mounts."},{"title":"Portfolio opacity","description":"Leaders lack a clear view of application health, cost, and risk."},{"title":"Inconsistent guardrails","description":"Security, integration, and lifecycle policies are applied unevenly."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Governance maturity view","description":"Leadership sees where standards, portfolio, and controls stand today."},{"title":"Prioritised improvement plan","description":"Initiatives are ordered by risk reduction and delivery enablement."},{"title":"Investment clarity","description":"Your technology leaders can fund the right governance fixes first."}]}}'::jsonb,
  faq_intro = 'Common questions about the Technology Governance assessment.'
WHERE variant_id = 121;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Technology governance maturity report', 'Scored assessment across portfolio management, architecture standards, vendor governance, and delivery controls, with evidence and specific gaps documented.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Investment and portfolio control findings', 'Analysis of where technology spend is poorly governed, misaligned to strategy, or lacking accountability, with specific improvement recommendations.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Architecture standards gap analysis', 'Documented drift from agreed standards, concentration of technical debt, and non-standard choices creating future integration or compliance risk.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (121, 'Prioritised improvement roadmap', 'Sequenced actions across governance dimensions, with effort estimates and dependencies framed for CIO and board-level decision-making.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'What does the maturity model cover?', 'The assessment covers four dimensions: technology portfolio and investment governance, enterprise architecture standards and compliance, vendor and third-party oversight, and delivery and programme governance. The DigitalQatalyst team confirms which are in scope during the kick-off.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'What documentation do you need from us?', 'Portfolio records, architecture principles documents, vendor contracts, and delivery governance artefacts such as project status reports or gate review outputs. Gaps in documentation are themselves findings.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'How is the maturity model calibrated to our organisation?', 'The DigitalQatalyst team aligns the scoring model to your organisation''s size, sector, and regulatory context in the first day of the engagement so findings are relevant rather than generic.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'Can this support a broader digital or IT transformation programme?', 'Yes. The roadmap is designed to feed directly into transformation planning, enterprise architecture reviews, or an operating model redesign.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (121, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We confirm scope, maturity model, and stakeholder availability before the engagement begins.', 4);

-- Technology Governance (High-Impact) - Design (variant 122)
UPDATE product_content SET
  description = 'Design a technology governance operating model that aligns portfolio decisions, architecture standards, vendor oversight, and delivery controls to your strategy, with the specifications and adoption plan your teams need to implement it.',
  positioning = 'A technology governance blueprint that translates strategy into accountable decisions, consistent architecture, and disciplined delivery.',
  hero_summary = 'Design a technology governance operating model that aligns portfolio decisions, architecture standards, vendor oversight, and delivery controls to your strategy, with the specifications and adoption plan your teams need to implement it.',
  overview_paragraphs = '["The Technology Governance Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines technology governance models and build-ready specifications.","Turn technology governance goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for cios, enterprise architecture & pmo leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate technology governance requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Decision rights and accountabilities defined across all governance dimensions","Architecture review board and portfolio governance ready to implement","Adoption plan included so governance changes embed without stalling delivery"]'::jsonb,
  why_it_matters = '{"hook":"Technology governance is what turns ambitious delivery into sustainable, risk-aware progress.","problemParagraph":"Many organisations document governance without designed decision forums, standards catalogues, or specifications platform teams can follow. This design engagement defines technology governance models and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined decision rights","description":"Architecture and security approvals lack clear forums and criteria."},{"title":"Standards catalogue gaps","description":"Patterns for integration, data, and security are incomplete or outdated."},{"title":"Operational ambiguity","description":"Teams lack specs for tooling, workflows, and compliance reporting."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Designed governance models","description":"Forums, roles, and decision paths are clear and actionable."},{"title":"Consistent standards","description":"Architecture and control requirements are defined upfront."},{"title":"Implementation-ready specs","description":"Platform teams receive artefacts that accelerate governed delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about designing a Technology Governance operating model.'
WHERE variant_id = 122;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Technology governance operating model', 'Documented decision rights, governance bodies, meeting cadences, escalation paths, and accountabilities across portfolio, architecture, vendor, and delivery governance.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Architecture review board design', 'Membership, mandate, decision criteria, review process, and exception procedures for your architecture governance function, ready to stand up.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Portfolio governance process specifications', 'Investment approval workflows, prioritisation criteria, performance tracking templates, and reporting formats for your technology portfolio function.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (122, 'Implementation handover package', 'Role descriptions, templates, tooling recommendations, and an adoption plan sequenced to minimise disruption to current delivery programmes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'Do we need an assessment before starting the design?', 'An assessment provides the evidence base for design priorities. Existing audit findings, architecture reviews, or previous governance reports can substitute if a fresh assessment has not been run.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'How do you design governance that works with our existing structures?', 'The design phase begins with a current-state review. The DigitalQatalyst team maps existing committees, forums, and reporting lines before designing the new model so it complements rather than conflicts with what already works.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'Can the design be implemented in phases?', 'Yes. The implementation handover package includes a phased adoption plan sequenced by impact and readiness. Quick-win governance changes are separated from longer-term structural redesigns.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'What tooling do you recommend for technology governance?', 'Tooling recommendations are included in the handover package, covering portfolio management platforms, architecture repository tools, and reporting tooling. The DigitalQatalyst team aligns recommendations to your existing technology estate.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (122, 'How do we get started?', 'Book a scoping call with the DigitalQatalyst team. We review your current governance maturity, objectives, and any existing documentation before confirming the design scope.', 4);

-- Technology Governance (High-Impact) - AI Design (variant 123)
UPDATE product_content SET
  description = 'Validate where AI can strengthen technology governance, design responsible decision-support workflows, and produce deployment-ready specifications so build investment goes into AI use cases that are feasible, governed, and aligned to your architecture standards.',
  positioning = 'AI-assisted technology governance starts with validated use cases and responsible design, not experimentation.',
  hero_summary = 'Validate where AI can strengthen technology governance, design responsible decision-support workflows, and produce deployment-ready specifications so build investment goes into AI use cases that are feasible, governed, and aligned to your architecture standards.',
  overview_paragraphs = '["The Technology Governance AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for technology governance, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cios, enterprise architecture & pmo leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for technology governance.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Use cases validated against data availability and regulatory constraints before build","Responsible AI assessment included for every prioritised use case","Deployment specifications prevent rework when the build phase begins"]'::jsonb,
  why_it_matters = '{"hook":"Technology governance is what turns ambitious delivery into sustainable, risk-aware progress.","problemParagraph":"Many organisations apply AI to your technology governance model without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for technology governance lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for technology governance are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Key questions about AI design for Technology Governance.'
WHERE variant_id = 123;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'AI use-case register for technology governance', 'Validated use cases for AI in portfolio management, architecture review, vendor oversight, and delivery governance, each assessed for feasibility and regulatory compatibility.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'Responsible AI assessment', 'Documented findings on data quality, bias risk, explainability requirements, and applicable AI regulations for each prioritised use case.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'AI workflow designs', 'End-to-end workflow specifications showing how AI outputs integrate into governance decision points, with human-in-the-loop controls at each critical step.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (123, 'Deployment specification package', 'Technical and governance requirements for each approved use case, including model criteria, data pipelines, guardrails, and monitoring configurations.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'What AI use cases apply to technology governance?', 'Common validated use cases include portfolio health analytics, architecture compliance drift detection, vendor risk scoring from contract and performance data, and delivery performance prediction. The DigitalQatalyst team works with your governance context to prioritise.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'What data do you need access to during the design phase?', 'Data inventories, schema documentation, and sample datasets for feasibility assessment. No production data is processed during design; the engagement works from specifications and representative samples.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'How do you assess responsible AI risk for governance functions?', 'The assessment covers decision significance, explainability obligations, data provenance, and the consequences of model error in each governance context. High-risk decision points automatically require human-in-the-loop controls in the workflow design.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'Do we need an existing technology governance model before this engagement?', 'A functioning governance model makes use-case identification more precise, but the DigitalQatalyst team can run this engagement alongside a governance design phase.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (123, 'How do we get started?', 'Request a consultation with the DigitalQatalyst team. We will review your current governance tooling, data landscape, and AI objectives before confirming the scope.', 4);

-- Technology Governance (High-Impact) - Deploy (variant 124)
UPDATE product_content SET
  description = 'Implement your technology governance operating model with configured tooling, integrated data sources, tested processes, and a controlled handover that leaves your CIO and architecture teams running confidently.',
  positioning = 'From governance design to live operations: configured tooling, integrated data, and your team trained to govern technology at scale.',
  hero_summary = 'Implement your technology governance operating model with configured tooling, integrated data sources, tested processes, and a controlled handover that leaves your CIO and architecture teams running confidently.',
  overview_paragraphs = '["The Technology Governance Deploy service delivers configured, tested capabilities with structured integration, quality assurance, and handover to your operations team. This implementation delivers configured, tested capabilities with structured handover.","Implement agreed technology governance changes through managed configuration, integration, testing, and controlled launch support."]'::jsonb,
  audience_description = 'Built for cios, enterprise architecture & pmo leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement delivers configured, tested, and validated technology governance assets aligned to approved scope.","Each output supports go-live readiness and structured handover to your operations team."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Twelve-week phased delivery with named milestones and governance checkpoints","First governance reporting cycle completed before handover closes","Training and runbooks ensure your team operates independently from go-live"]'::jsonb,
  why_it_matters = '{"hook":"Technology governance is what turns ambitious delivery into sustainable, risk-aware progress.","problemParagraph":"Many organisations stall between approved designs and production for your technology governance model, with integration gaps, quality risks, and delayed go-live. This implementation delivers configured, tested capabilities with structured handover.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Stalled implementation","description":"Approved designs for technology governance sit idle while teams struggle to coordinate build and integration."},{"title":"Quality and integration risk","description":"Testing gaps and platform dependencies threaten go-live timelines and stability."},{"title":"Unclear handover","description":"Operations teams lack the documentation and knowledge transfer needed to run live systems."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Production-ready delivery","description":"Capabilities are built, tested, and validated against agreed acceptance criteria."},{"title":"Integrated platforms","description":"Solutions are deployed with security, governance, and platform requirements met."},{"title":"Confident go-live","description":"Structured handover equips your teams to operate and evolve the capability."}]}}'::jsonb,
  faq_intro = 'Key questions about deploying a Technology Governance operating model.'
WHERE variant_id = 124;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Configured technology governance platform', 'Portfolio management, architecture repository, or governance tooling fully configured to your operating model, with all agreed integrations live and reporting automated.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Data integration documentation', 'Documented connections between governance tooling and portfolio, financial, vendor, and architecture data sources, with data flow diagrams and refresh schedules.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Process activation evidence', 'Records of architecture review board, portfolio governance, and vendor oversight processes tested and signed off by your governance stakeholders.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (124, 'Operational handover package', 'Runbooks, administrator guides, training materials, and a first-cycle governance calendar so your teams operate without dependency on the DigitalQatalyst team.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'Which governance platforms can you configure?', 'Planview, ServiceNow IT Business Management, LeanIX, Ardoq, and portfolio management tooling in Microsoft or Atlassian ecosystems. Platform selection is confirmed during pre-deployment scoping with the DigitalQatalyst team.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'What data sources do you typically integrate?', 'Financial systems for investment data, project management tools for delivery status, architecture repositories, vendor contract management systems, and HR systems for resource data. Integration scope is confirmed in week one.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'How do you handle governance process changes mid-deployment?', 'A change control process is established in week one. Minor changes are absorbed; significant scope changes are assessed and agreed before implementation to protect the timeline.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'What is the first governance cycle output we will see?', 'By the end of week twelve your portfolio reporting, architecture review calendar, and vendor oversight process will have completed their first cycle, producing real governance outputs rather than test artefacts.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (124, 'How do we get started?', 'Share your governance design specification and the DigitalQatalyst team will scope the deployment in detail and confirm the timeline within five working days.', 4);

-- Technology Governance (High-Impact) - AI Deploy (variant 125)
UPDATE product_content SET
  description = 'Deploy AI decision-support capabilities into your technology governance function with live monitoring, human-in-the-loop controls, and an operations model that keeps your CIO and architecture teams in charge of every material decision.',
  positioning = 'AI in production for technology governance: validated models, governed decisions, and your team trained to manage them.',
  hero_summary = 'Deploy AI decision-support capabilities into your technology governance function with live monitoring, human-in-the-loop controls, and an operations model that keeps your CIO and architecture teams in charge of every material decision.',
  overview_paragraphs = '["The Technology Governance AI Deploy service deploys governed AI capabilities into production with monitoring, safety controls, and operational handover. This AI implementation deploys governed capabilities with monitoring and handover built in.","Put AI-enabled technology governance workflows into production with security, governance, and adoption built in from day one."]'::jsonb,
  audience_description = 'Built for cios, enterprise architecture & pmo leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement deploys production AI capabilities for technology governance with monitoring and safety controls.","You receive operational runbooks and validation evidence before handover."]'::jsonb,
  delivery_process = '{"totalDuration":"12 Weeks","steps":[{"step":1,"title":"Prepare","duration":"2 Weeks","body":"We confirm scope, environments, and acceptance criteria before build.","whatHappens":"Technical readiness and delivery planning","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Build","duration":"6-8 Weeks","body":"We implement, integrate, and test against agreed requirements.","whatHappens":"Sprints, QA cycles, and stakeholder reviews","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Go live","duration":"2 Weeks","body":"We support launch, validation, and handover to your operations team.","whatHappens":"Go-live readiness, cutover, and knowledge transfer","dqEffort":"high","yourEffort":"medium"}]}'::jsonb,
  package_highlights = '["Parallel-run phase validates AI accuracy against actual governance decisions before full cutover","Every material AI recommendation requires human approval before action is taken","Operations training ensures your team governs the AI, not the other way around"]'::jsonb,
  why_it_matters = '{"hook":"Technology governance is what turns ambitious delivery into sustainable, risk-aware progress.","problemParagraph":"Many AI initiatives for your technology governance model fail to reach production, blocked by integration complexity, safety concerns, and missing operational readiness. This AI implementation deploys governed capabilities with monitoring and handover built in.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"AI stuck in pilot","description":"Promising AI designs for technology governance fail to reach production due to integration and operational barriers."},{"title":"Safety and compliance gaps","description":"Monitoring, auditability, and responsible AI controls are not yet in place."},{"title":"Operational blind spots","description":"Teams lack runbooks and performance visibility for live AI capabilities."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Live AI capabilities","description":"AI is deployed in production with orchestration and monitoring built in."},{"title":"Governed operations","description":"Safety controls, compliance checks, and audit trails support responsible use at scale."},{"title":"Operational readiness","description":"Runbooks and handover materials equip teams to manage AI in production."}]}}'::jsonb,
  faq_intro = 'Key questions about AI deployment for Technology Governance.'
WHERE variant_id = 125;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Production AI deployment for technology governance', 'AI models live in your environment, connected to portfolio, architecture, and vendor data sources, processing recommendations within agreed accuracy and latency thresholds.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Human-in-the-loop workflow documentation', 'Configured approval checkpoints, escalation paths, and override procedures for each AI-supported governance decision, documented for audit and regulatory review.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Governance AI monitoring dashboard', 'Real-time view of model outputs, recommendation volumes, acceptance rates, and governance decision outcomes with configurable thresholds and alerting.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (125, 'Operations and retraining guide', 'Step-by-step procedures for your governance teams to manage model performance, trigger retraining cycles, and document AI-influenced decisions for audit purposes.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'Which AI use cases can you put into production for technology governance?', 'Portfolio health analytics, architecture compliance drift detection, vendor risk scoring, and delivery performance prediction are the most common production deployments. The DigitalQatalyst team builds from your validated AI design specifications.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'How do you ensure AI does not make governance decisions without approval?', 'Human-in-the-loop checkpoints are configured before production cutover. Every AI recommendation that influences a governance decision routes to a named accountable leader for approval. The approval audit trail is maintained in the governance platform.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'What happens if a model recommendation is consistently wrong?', 'The monitoring dashboard surfaces acceptance rates and override frequencies weekly. The operations guide includes retraining triggers and the DigitalQatalyst team provides hypercare support during the first two weeks post-launch.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'Do we need AI design specifications before this engagement?', 'Yes. The AI Deploy engagement builds directly from specifications produced in an AI Design phase. If those are not complete, the DigitalQatalyst team can run a combined design and deployment programme.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (125, 'How do we get started?', 'Share your AI design specifications and the DigitalQatalyst team will confirm environment readiness, integration requirements, and the deployment schedule within one week.', 4);

-- Technology Governance (High-Impact) - Managed (variant 126)
UPDATE product_content SET
  description = 'Operate your technology governance framework continuously, with monthly portfolio reporting, quarterly architecture reviews, vendor oversight, and proactive optimisation so your CIO always has an accurate picture of investment alignment and technology risk.',
  positioning = 'Named governance operations, monthly reporting, and continuous optimisation so technology governance keeps pace with your business.',
  hero_summary = 'Operate your technology governance framework continuously, with monthly portfolio reporting, quarterly architecture reviews, vendor oversight, and proactive optimisation so your CIO always has an accurate picture of investment alignment and technology risk.',
  overview_paragraphs = '["The Technology Governance Managed Service service runs SLA-backed operations with continuous monitoring, optimisation, and lifecycle governance. This managed service provides SLA-backed operations and continuous improvement.","Run and improve technology governance with ongoing monitoring, reporting, and optimisation so performance keeps pace with your business."]'::jsonb,
  audience_description = 'Built for cios, enterprise architecture & pmo leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This managed service covers ongoing operations, reporting, and improvement for technology governance - managed.","You receive predictable SLA-backed support aligned to agreed service levels."]'::jsonb,
  delivery_process = '{"totalDuration":"Ongoing","steps":[{"step":1,"title":"Onboard","duration":"Week 1","body":"We align on scope, SLAs, access, and how we will run the service with your team.","whatHappens":"Scope alignment, SLA setup, and access provisioning","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Operate","duration":"Ongoing","body":"We run agreed operations with monitoring, incident response, and SLA-backed reporting.","whatHappens":"Monitoring, incident response, and service reporting","dqEffort":"high","yourEffort":"low"},{"step":3,"title":"Improve","duration":"Ongoing","body":"We review performance, apply optimisations, and keep the service aligned as your needs change.","whatHappens":"Performance reviews, optimisations, and roadmap updates","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Named DigitalQatalyst team with defined SLAs for reporting, escalations, and reviews","Monthly portfolio reports and quarterly architecture reviews included as standard","Proactive regulatory and technology change monitoring keeps governance current"]'::jsonb,
  why_it_matters = '{"hook":"Technology governance is what turns ambitious delivery into sustainable, risk-aware progress.","problemParagraph":"Many organisations struggle to sustain performance across your technology governance model after go-live, with reactive support, rising costs, and declining platform value. This managed service provides SLA-backed operations and continuous improvement.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Reactive operations","description":"technology governance issues are addressed after impact, not prevented through proactive management."},{"title":"Declining performance","description":"Platform value erodes without continuous optimisation and lifecycle governance."},{"title":"Unpredictable support","description":"Service levels and escalation paths are unclear when teams need help most."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"SLA-backed operations","description":"Predictable service levels and structured incident management keep platforms running."},{"title":"Continuous optimisation","description":"Proactive monitoring and improvement sustain performance and user satisfaction."},{"title":"Lifecycle governance","description":"Regular reviews and reporting align platform evolution with business priorities."}]}}'::jsonb,
  faq_intro = 'Key questions about the Technology Governance managed service.'
WHERE variant_id = 126;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Monthly technology portfolio report', 'Structured report covering investment alignment, delivery performance, risk indicators, and exception items, formatted for CIO and board-level review.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Quarterly architecture review report', 'Assessment of architecture standards compliance, technical debt trends, non-standard exception status, and recommended actions for your enterprise architecture function.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Vendor performance and risk summary', 'Ongoing view of vendor contract performance, risk indicators, upcoming renewals, and escalation items requiring CIO or commercial team attention.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (126, 'Governance optimisation recommendations', 'Quarterly recommendations for process improvements, tooling enhancements, or governance model adjustments based on performance data and changes in your technology landscape.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'What does the monthly managed service include?', 'Continuous portfolio and investment monitoring, a monthly performance report for CIO and board use, ongoing vendor oversight, and escalation support for governance issues requiring executive attention.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'How are architecture reviews structured in the managed service?', 'Quarterly architecture review cycles cover standards compliance, technical debt trends, and outstanding non-standard exceptions. Results feed into the quarterly governance performance review with your CIO and architecture leaders.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'Can the managed service adapt as our technology strategy changes?', 'Yes. Scope and reporting are reviewed quarterly. Changes to portfolio scope, new governance domains, or revised strategic priorities are incorporated through a change request without disrupting ongoing operations.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'How do you handle a governance escalation or investment decision under time pressure?', 'The DigitalQatalyst team provides named points of contact for escalations. Response SLAs are defined by issue severity. For investment decisions, the team can produce targeted analysis within agreed timescales to support the decision-making process.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (126, 'How do we get started?', 'The DigitalQatalyst team runs a two-week onboarding to establish governance baselines, confirm SLAs, connect monitoring tooling, and set the governance calendar before steady-state operations begin.', 4);

-- DevSecOps Automation (High-Impact) - Assess (variant 127)
UPDATE product_content SET
  description = 'Identify where your software delivery pipeline leaks speed, introduces security risk, or fails to meet reliability standards. The DigitalQatalyst team maps DevSecOps maturity across your toolchain and returns a prioritised roadmap your engineering and security leaders can act on.',
  positioning = 'A structured assessment of your delivery pipeline that shows where automation gaps slow releases and where security controls are missing.',
  hero_summary = 'Identify where your software delivery pipeline leaks speed, introduces security risk, or fails to meet reliability standards. The DigitalQatalyst team maps DevSecOps maturity across your toolchain and returns a prioritised roadmap your engineering and security leaders can act on.',
  overview_paragraphs = '["The DevSecOps Automation Assess service reviews your current state, surfaces priority gaps, and leaves you with evidence-led recommendations stakeholders can act on. This assessment maps DevSecOps maturity and returns prioritised improvements your engineering leaders can act on.","See how DevSecOps automation performs today, identify the highest-impact gaps, and leave with prioritised next steps and a practical roadmap."]'::jsonb,
  audience_description = 'Built for ctos, engineering, security & devops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement reviews devsecops automation across business operations and productivity.","You receive practical findings and a prioritised roadmap for next steps."]'::jsonb,
  delivery_process = '{"totalDuration":"1 Week","steps":[{"step":1,"title":"Scope","duration":"Days 1-2","body":"We align on your goals, stakeholders, and assessment focus so the week stays targeted.","whatHappens":"Kick-off, context gathering, and assessment scope","dqEffort":"medium","yourEffort":"medium","active":true},{"step":2,"title":"Assess","duration":"Days 3-4","body":"We review your current state, surface priority gaps, and gather evidence your leadership can act on.","whatHappens":"Current-state review, gap analysis, and evidence capture","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Advise","duration":"Day 5","body":"We share findings, recommendations, and practical next steps so you know what to prioritise in the marketplace.","whatHappens":"Findings playback, recommendations, and next-step roadmap","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Fixed-scope assessment with findings delivered within one week","Covers security, velocity, and reliability dimensions of your pipeline","No obligation to proceed with subsequent design or deployment"]'::jsonb,
  why_it_matters = '{"hook":"DevSecOps practices determine how fast you can ship, and how confidently you can scale.","problemParagraph":"Many organisations deliver software with manual pipelines, late security testing, and inconsistent release practices. This assessment maps DevSecOps maturity and returns prioritised improvements your engineering leaders can act on.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Manual delivery pipelines","description":"Builds and deployments rely on tribal knowledge instead of automation."},{"title":"Late security feedback","description":"Vulnerabilities are found after merge instead of during development."},{"title":"Release inconsistency","description":"Teams ship on different cadences without shared quality gates."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Pipeline priority map","description":"You know which toolchain, process, and control gaps to fix first."},{"title":"Ranked improvement backlog","description":"Initiatives are ordered by delivery speed, risk, and dependency."},{"title":"Leadership-ready roadmap","description":"Recommendations support governed engineering transformation funding."}]}}'::jsonb,
  faq_intro = 'Key questions about the DevSecOps automation assessment.'
WHERE variant_id = 127;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'DevSecOps maturity assessment', 'Ratings across pipeline automation, security integration, test coverage, and release reliability, with evidence and specific gaps for each dimension.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'Security control gap report', 'Missing or misconfigured controls in SAST, DAST, dependency scanning, secrets detection, and container security, ranked by exploitability.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'Delivery velocity baseline', 'Current lead time, deployment frequency, change failure rate, and mean time to restore, with analysis of the pipeline stages causing the most drag.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (127, 'Prioritised remediation roadmap', 'Sequenced actions addressing the highest-risk gaps first, with effort estimates and the expected improvement in release quality and speed.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'Which pipelines and platforms does the assessment cover?', 'Any CI/CD toolchain: GitHub Actions, GitLab CI, Jenkins, Azure DevOps, and others. The DigitalQatalyst team confirms scope during the initial scoping call.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'Do you need access to our source code?', 'We review pipeline configuration, scan results, and deployment logs. Source code access is not required unless specific vulnerability patterns need tracing.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'What do we get at the end?', 'A maturity assessment, a security control gap report, a velocity baseline, and a prioritised remediation roadmap.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (127, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team will confirm which pipelines and teams are in scope before work begins.', 3);

-- DevSecOps Automation (High-Impact) - Design (variant 128)
UPDATE product_content SET
  description = 'Design a DevSecOps automation programme that closes your pipeline security gaps, accelerates release cycles, and gives your engineering teams clear, build-ready specifications for every workflow change.',
  positioning = 'A design engagement that produces a complete DevSecOps automation blueprint ready for your engineering teams to implement.',
  hero_summary = 'Design a DevSecOps automation programme that closes your pipeline security gaps, accelerates release cycles, and gives your engineering teams clear, build-ready specifications for every workflow change.',
  overview_paragraphs = '["The DevSecOps Automation Design service turns your goals into user-centred designs and implementation-ready specifications your delivery teams can build against. This design engagement defines delivery workflows and build-ready specifications.","Turn DevSecOps automation goals into a delivery-ready blueprint with journeys, workflows, integrations, controls, and an adoption plan your teams can execute."]'::jsonb,
  audience_description = 'Built for ctos, engineering, security & devops leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement produces design artefacts that translate devsecops automation requirements into build-ready specifications.","Each output is structured for governance review and handover to delivery teams."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Design-only engagement: no build commitment required","Platform-agnostic design that works with your existing toolchain","Security controls specified at every pipeline stage"]'::jsonb,
  why_it_matters = '{"hook":"DevSecOps practices determine how fast you can ship, and how confidently you can scale.","problemParagraph":"Many organisations adopt DevSecOps tools without designed pipelines, policy-as-code models, or specifications platform teams can implement. This design engagement defines delivery workflows and build-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Undefined pipeline models","description":"CI/CD stages, approvals, and environments are not designed end to end."},{"title":"Security control gaps","description":"Scanning, secrets, and policy enforcement lack consistent standards."},{"title":"Platform ambiguity","description":"Teams lack specs for tooling integration and developer experience."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Aligned pipeline designs","description":"Workflows balance speed, quality, and security with clear gates."},{"title":"Consistent DevSecOps standards","description":"Controls and policies are defined for repeatable adoption."},{"title":"Implementation-ready specs","description":"Platform teams receive artefacts that accelerate pipeline delivery."}]}}'::jsonb,
  faq_intro = 'Key questions about the DevSecOps automation design engagement.'
WHERE variant_id = 128;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Pipeline architecture blueprint', 'End-to-end design of your CI/CD stages including trigger logic, parallelisation, caching strategy, and failure-handling patterns.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Security toolchain specification', 'Tools, scan configurations, threshold policies, and integration patterns for every security gate in the pipeline.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Workflow and governance design', 'Branch strategy, environment promotion rules, approval gates, and audit trail requirements documented for implementation.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (128, 'Developer adoption plan', 'Training approach, inner-loop tooling recommendations, and rollout phasing to minimise disruption to active delivery teams.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (128, 'Can we keep our existing CI/CD platform?', 'Yes. The design is built around your current toolchain wherever it meets requirements. Replacements are only recommended where existing tools create unresolvable gaps.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (128, 'How do you balance security controls with developer speed?', 'Security gates are designed to run in parallel where possible and block only on critical findings. The developer experience plan ensures controls add minimal friction to the inner loop.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (128, 'How do we get started?', 'Contact the DigitalQatalyst team to share your current pipeline inventory and confirm which teams and platforms are in scope for the design.', 2);

-- DevSecOps Automation (High-Impact) - AI Design (variant 129)
