  hero_summary = 'Validate which AI capabilities can genuinely improve incident resolution and IT operations efficiency for your organisation, then produce responsible workflow designs and deployment specifications ready for build.',
  overview_paragraphs = '["The IT Operations & Support AI Design service validates AI use cases, defines responsible workflows, and produces deployment-ready specifications before build investment. This AI design engagement defines responsible workflows and deployment-ready specifications.","Define the AI use cases that matter for IT operations and employee support services, with data requirements, guardrails, and specifications ready to build."]'::jsonb,
  audience_description = 'Built for cios, it operations & service desk leaders who need clear scope, practical outputs, and governance-aligned delivery.',
  deliverables_summary = '["This engagement validates AI use cases and defines responsible workflows for it operations & support.","You receive specifications that balance innovation with governance before build investment."]'::jsonb,
  delivery_process = '{"totalDuration":"4 Weeks","steps":[{"step":1,"title":"Discover","duration":"1 Week","body":"We align on goals, constraints, and success measures with your stakeholders.","whatHappens":"Kick-off, stakeholder interviews, and scope confirmation","dqEffort":"high","yourEffort":"medium","active":true},{"step":2,"title":"Design","duration":"2-3 Weeks","body":"We produce experience, workflow, and specification artefacts for review.","whatHappens":"Design workshops, reviews, and iteration cycles","dqEffort":"high","yourEffort":"medium"},{"step":3,"title":"Handover","duration":"1 Week","body":"We finalise specifications and agree the path to implementation.","whatHappens":"Governance sign-off and delivery backlog handover","dqEffort":"medium","yourEffort":"low"}]}'::jsonb,
  package_highlights = '["Human approval gates and blast-radius limits designed into every automated remediation workflow","Data readiness report tells you exactly which operational data needs improvement before build","Specifications designed for your existing ITSM and monitoring platform architecture"]'::jsonb,
  why_it_matters = '{"hook":"IT operations keep critical platforms available, secure, and fit for evolving business needs.","problemParagraph":"Many organisations apply AI to your IT service operations without validated use cases, unclear guardrails, or specifications ready for controlled deployment. This AI design engagement defines responsible workflows and deployment-ready specifications.","before":{"eyebrow":"Without this service","title":"Typical gaps","items":[{"title":"Unvalidated AI use cases","description":"AI ambitions for it operations & support lack structured validation against business value and feasibility."},{"title":"Missing guardrails","description":"Responsible AI controls and human-in-the-loop workflows are not yet defined."},{"title":"Deployment uncertainty","description":"Teams cannot move from concept to build without clear specifications and risk controls."}]},"after":{"eyebrow":"With this service","title":"What changes","items":[{"title":"Validated use cases","description":"AI opportunities for it operations & support are prioritised with clear value hypotheses and success criteria."},{"title":"Responsible workflows","description":"Human oversight, safety controls, and governance are designed into every workflow."},{"title":"Deployment-ready designs","description":"Specifications and prototypes de-risk investment and accelerate production deployment."}]}}'::jsonb,
  faq_intro = 'Questions about the IT operations AI design engagement.'
WHERE variant_id = 135;

INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'AI use-case scorecard for IT operations', 'Each candidate use case rated by operational impact, data feasibility, risk, and implementation complexity, with a clear build recommendation and the sequencing rationale.', 0);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Responsible AI workflow designs', 'Workflow diagrams for each validated use case showing AI decision points, human approval gates, rollback triggers, blast-radius limits, and the conditions under which automated remediation is prohibited.', 1);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Operational data readiness report', 'Assessment of your monitoring, log, and ITSM data against the requirements of each validated AI use case, with specific data improvement actions needed before build can begin.', 2);
INSERT INTO variant_deliverables (variant_id, title, description, sort_order) VALUES (135, 'Technical deployment specification', 'Model inputs, outputs, ITSM and monitoring integration requirements, infrastructure needs, and the acceptance criteria for validating AI performance in a staging environment before production.', 3);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'Which AI use cases are most commonly validated for IT operations?', 'Intelligent alert correlation and noise reduction, anomaly detection for infrastructure metrics, predictive disk and capacity failure, and automated safe remediation playbooks are the most frequently scoped. The DigitalQatalyst team validates each against your specific operational data.', 0);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'How do you ensure AI remediation cannot cause a wider outage?', 'Blast-radius limits and scope boundaries are core design requirements, not optional additions. Every automated remediation workflow specifies what the AI is permitted to do, the conditions that must be true before action is taken, and the rollback trigger if the action does not produce the expected result.', 1);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'What monitoring data do we need before AI design is viable?', 'The data readiness assessment evaluates your monitoring coverage, log retention, and alert history. Gaps are identified with specific remediation steps. Many organisations find targeted monitoring improvements take weeks rather than months.', 2);
INSERT INTO product_faqs (variant_id, question, answer, sort_order) VALUES (135, 'How do we get started?', 'Request a consultation. The DigitalQatalyst team reviews your ITSM platform, monitoring stack, and operational data landscape to shape the engagement scope.', 3);

